import { useCallback, useEffect, useState } from "react";
import {
  Route,
  Routes,
  BrowserRouter,
  Navigate
} from "react-router-dom";

import "./App.css";
import Users from "./user/pages/Users.js";
import NewPlace from "./places/pages/NewPlace.js";
import MainNavigation from "../src/shared/components/Navigation/MainNavigation.js";
import Footer from "./shared/components/Navigation/Footer.js";
import UserPlaces from "./places/pages/UserPlaces.js";
import UpdatePlace from "./places/pages/Updateplace.js";
import Auth from "./user/pages/Auth.js";
import { AuthContext } from "./context/AuthContext.js";
import { ThemeProvider } from "./context/ThemeContext.js";
import { ToastProvider } from "./context/ToastContext.js";
import Explore from "./places/pages/Explore.js";
import PostDetail from "./places/pages/PostDetail.js";
import ScrollToTop from "./shared/components/UiElements/ScrollToTop.js";
import "../src/shared/components/UiElements/Toast.css";

let logoutTimer;

const App = () => {
  const [token, setToken] = useState(null);
  const [expirationDate, setExpirationDate] = useState(null);
  const [userId, setuserId] = useState(null);
  let routes;

  const login = useCallback((user_id, token, expiration) => {
    setToken(token);
    const future = new Date(new Date().getTime() + 1000 * 60 * 60);
    const tokenExpirationDate = expiration || future;
    setExpirationDate(tokenExpirationDate);
    localStorage.setItem(
      "userData",
      JSON.stringify({
        user_id,
        token,
        expiration: tokenExpirationDate.toISOString(),
      })
    );
    setuserId(user_id);
  }, []);

  const logout = useCallback(() => {
    setToken(null);
    setExpirationDate(null);
    setuserId(null);
    localStorage.removeItem("userData");
  }, []);

  useEffect(() => {
    if (token && expirationDate) {
      const reaminingTime = expirationDate - new Date().getTime();
      logoutTimer = setTimeout(logout, reaminingTime);
    } else {
      clearTimeout(logoutTimer);
    }
  }, [token, logout, expirationDate]);

  useEffect(() => {
    const storedData = JSON.parse(localStorage.getItem("userData"));
    if (
      storedData &&
      storedData.token &&
      new Date(storedData.expiration) > new Date()
    ) {
      login(
        storedData.user_id,
        storedData.token,
        new Date(storedData.expiration)
      );
    }
  }, [login]);

  if (token) {
    routes = (
      <Routes>
        <Route path="/" element={<Users />} />
        <Route path="/explore" element={<Explore />} />
        <Route path="/post/:pid" element={<PostDetail />} />
        <Route path="/places/new" element={<NewPlace />} />
        <Route path="/places/:pid" element={<UpdatePlace />} />
        <Route path="/:userId/places" element={<UserPlaces />} />
        <Route path="*" element={<Navigate to="/" replace />} />
      </Routes>
    );
  } else {
    routes = (
      <Routes>
        <Route path="/" element={<Users />} />
        <Route path="/explore" element={<Explore />} />
        <Route path="/post/:pid" element={<PostDetail />} />
        <Route path="/auth" element={<Auth />} />
        <Route path="/:userId/places" element={<UserPlaces />} />
        <Route path="*" element={<Navigate to="/auth" replace />} />
      </Routes>
    );
  }

  return (
    <ThemeProvider>
      <ToastProvider>
        <AuthContext.Provider
          value={{
            isLoggedIn: !!token,
            token: token,
            login: login,
            logout: logout,
            userId: userId,
          }}
        >
          <BrowserRouter>
            <MainNavigation />
            <main>{routes}</main>
            <Footer />
            <ScrollToTop />
          </BrowserRouter>
        </AuthContext.Provider>
      </ToastProvider>
    </ThemeProvider>
  );
};

export default App;
